import { React, useState } from 'react'
import Button from '@mui/material/Button';
import { FormControl, Stack, Box, InputLabel, Input, IconButton, InputAdornment, Typography, Link, AlertTitle, Alert } from '@mui/material';
import Visibility from '@mui/icons-material/Visibility';
import VisibilityOff from '@mui/icons-material/VisibilityOff';
import { Link as RouterLink, useNavigate } from 'react-router-dom'
import useAuth from '../hooks/useAuth'
import appTheme from '../theme';
import supabaseClient from '../supabase.js'



const RegisterForm = () => {
    
    const [showPassword, setShowPassword] = useState(false);
    const [repeatPassword, setRepeatPassword] = useState('');
  
    const handleClickShowPassword = () => setShowPassword((show) => !show);
  
    const handleMouseDownPassword = (event) => {
      event.preventDefault();
    };

    const { dataUser, user } = useAuth()
    const [ errorMessage, setErrorMessage ] = useState('')
    

    const navigate = useNavigate()


    const handleSubmit = async(e) => {

        e.preventDefault()
        setErrorMessage('')

        if (dataUser.password !== repeatPassword) {
            setErrorMessage('Las contraseñas no coinciden');
            return;
          }
        
        try {
          
            const { error } = await supabaseClient.auth.signUp(user)

            if(error)
            {
                setErrorMessage(error.message)
            }
            else
            {
                navigate('/login')
            }

            setErrorMessage('')
        
            
          } catch(error)
          {
            setErrorMessage("Error inesperado. Volvé a intentarlo en unos minutos.")
          }
    }

  return (
        <>
        {   
            <Stack direction="column" sx={{
                    display: 'flex',
                    alignItems: 'center',
                }}>
                <form onSubmit={handleSubmit}>
                    <Box sx={{
                            margin: '2rem auto',
                            padding: '1rem',
                        }}>

                        <FormControl variant="standard" sx={{
                            width: '100%',
                            paddingBottom: '2rem',
                        }}  >
                        <InputLabel sx={{
                            fontSize: '14px',
                            color: appTheme.palette.primary.main,
                        
                        }} htmlFor="email">Email</InputLabel>
                        <Input
                            id="email"
                            type="text"
                            onChange={dataUser}
                            name="email"
                        />
                        </FormControl>
                        <FormControl sx={{ width: '100%', paddingBottom: '2rem' }} variant="standard" >
                        <InputLabel sx={{
                            fontSize: '14px',
                            color: appTheme.palette.primary.main,
                        
                        }} htmlFor="password">Contraseña</InputLabel>
                        <Input
                            id="password"
                            name="password"
                            type={showPassword ? 'text' : 'password'}
                            endAdornment={
                            <InputAdornment position="end">
                                <IconButton
                                aria-label="toggle password visibility"
                                onClick={handleClickShowPassword}
                                onMouseDown={handleMouseDownPassword}
                                color="primary"
                                >
                                {showPassword ? <VisibilityOff /> : <Visibility />}
                                </IconButton>
                            </InputAdornment>
                            }
                            onChange={dataUser}
                        />
                        </FormControl>
                        <FormControl sx={{ width: '100%' }} variant="standard" >
                        <InputLabel sx={{
                            fontSize: '14px',
                            color: appTheme.palette.primary.main,
                        }} htmlFor="password-repeat">Repetir contraseña</InputLabel>
                        <Input
                            id="password-repeat"
                            name="password-repeat"
                            type={showPassword ? 'text' : 'password'}
                            value={repeatPassword}
                            onChange={(e) => setRepeatPassword(e.target.value)}
                        />
                        </FormControl>
                        
                        {errorMessage && (
                        <Alert severity="error" icon={false} sx={{
                            marginTop: '20px'
                        }}  >
                            <AlertTitle sx={{
                            fontSize: '12px'
                        }}>{errorMessage}</AlertTitle>
                        </Alert>
                        )}
                    </Box>
                    <Box>
                        <Typography align="center" variant='subtitle2' color="primary.dark">¿Ya tenés una cuenta? <Link component={RouterLink} color="primary.dark" fontWeight={700} to="/login" >Ingresá</Link></Typography>
                        
                        
                    </Box>
                    
                    <Button variant="contained" sx={{
                        textTransform: 'capitalize',
                        fontSize: '18px',
                        fontFamily: 'Poppins',
                        fontWeight: 700,
                        width: '100%',
                        marginTop: '3rem',
                        marginBottom: '1rem'
                    }} type="submit">Registrarme</Button>
                </form>
                
            </Stack>            
}           
        </>
  )
}

export default RegisterForm
